No existing charm code. Here's a complete `_on_pebble_ready` handler with the three requested features, written as a self-contained example you can adapt:

```python
from __future__ import annotations

import dataclasses
import logging

import ops

logger = logging.getLogger(__name__)

CONTAINER_NAME = "myapp"
SERVICE_NAME = "myapp"
HEALTH_PORT = 8080


@dataclasses.dataclass
class Config:
    command: str

    @classmethod
    def from_charm(cls, charm: ops.CharmBase) -> Config:
        return cls(command=str(charm.config["command"]))


class MyCharm(ops.CharmBase):
    def __init__(self, framework: ops.Framework) -> None:
        super().__init__(framework)
        framework.observe(self.on[CONTAINER_NAME].pebble_ready, self._on_pebble_ready)
        framework.observe(self.on.database_relation_changed, self._on_database_relation_changed)

    def _on_pebble_ready(self, event: ops.PebbleReadyEvent) -> None:
        self._configure_workload(event.workload)

    def _on_database_relation_changed(self, event: ops.RelationChangedEvent) -> None:
        container = self.unit.get_container(CONTAINER_NAME)
        if not container.can_connect():
            event.defer()
            return
        self._configure_workload(container)

    def _configure_workload(self, container: ops.Container) -> None:
        config = Config.from_charm(self)
        env = self._database_env()

        layer: ops.pebble.LayerDict = {
            "summary": "myapp layer",
            "services": {
                SERVICE_NAME: {
                    "override": "replace",
                    "startup": "enabled",
                    "command": config.command,
                    "environment": env,
                    "on-check-failure": {
                        "http-health": "restart",
                    },
                },
            },
            "checks": {
                "http-health": {
                    "override": "replace",
                    "level": "ready",
                    "period": "10s",
                    "timeout": "3s",
                    "threshold": 3,
                    "http": {
                        "url": f"http://localhost:{HEALTH_PORT}/health",
                    },
                },
            },
        }

        container.add_layer(SERVICE_NAME, layer, combine=True)
        container.replan()
        logger.info("Workload configured and replanned")
        self.unit.status = ops.ActiveStatus()

    def _database_env(self) -> dict[str, str]:
        """Return environment variables sourced from the database relation."""
        relation = self.model.get_relation("database")
        if relation is None or not relation.app:
            return {}
        data = relation.data[relation.app]
        env: dict[str, str] = {}
        for key in ("host", "port", "dbname", "username", "password"):
            value = data.get(key)
            if value:
                env[f"DB_{key.upper()}"] = value
        return env
```

Key design decisions:

- **`_configure_workload`** is extracted so both `pebble_ready` and `database_relation_changed` can call it — avoids duplicating the layer definition.
- **`override: replace`** on both the service and check ensures the layer is always authoritative, not merged with stale state.
- **`on-check-failure: restart`** ties the HTTP check to the service lifecycle — Pebble restarts the service if the check fails `threshold` times.
- **`_database_env`** reads relation data from the remote app's databag (the standard pattern for database charm libraries like `data-platform-libs`). If your charm uses `DatabaseRequires`, replace this with the credential accessors from that library.
- The `database_relation_changed` handler defers if Pebble isn't ready yet, so ordering between the two events is safe.

You'll need matching entries in `charmcraft.yaml`:

```yaml
config:
  options:
    command:
      type: string
      description: Command to run as the workload process.
      default: "/usr/bin/myapp"

requires:
  database:
    interface: pgsql  # or mysql, etc.
    optional: true
```
